// Parser capteurs : smarthome/<piece>/<capteur>
var p = msg.topic.split("/");
if (p[1] === "predictions") return null;
var piece = p[1], capteur = p[2];
var st = flow.get("state") || {};
st[piece] = st[piece] || {};
var v = Number(msg.payload);
if (isNaN(v)) { try { v = JSON.parse(msg.payload).value; } catch(e) {} }
st[piece][capteur] = v;
st[piece].ts = Date.now();
flow.set("state", st);
node.status({fill:"green", shape:"dot", text: piece + "/" + capteur + " = " + v});
return msg;

// Moteur d'automatisation (declenche sur message capteur)
var p = msg.topic.split("/"); var piece = p[1], capteur = p[2];
var pr = flow.get("predictions") || {};
var mode = global.get("mode") || "present";
var h = new Date().getHours();
var out = [];

// Regle 1 : eclairage auto sur presence la nuit
if (capteur === "motion" && Number(msg.payload) === 1 && (h < 7 || h >= 19))
    out.push({ topic:"smarthome/"+piece+"/light/set", payload:"1" });

// Regle 2 : alerte intrusion en mode absent
if (capteur === "motion" && Number(msg.payload) === 1 && mode === "away"
    && (piece === "garage" || piece === "terrasse" || piece === "entree"))
    out.push({ topic:"smarthome/alerts", payload: JSON.stringify({type:"intrusion", piece:piece, ts:Date.now()}) });

// Regle 3 : chauffage anticipe (prediction IA)
if (pr[piece] && pr[piece].temp_next != null && pr[piece].temp_next < 19)
    out.push({ topic:"smarthome/"+piece+"/heating/set", payload:"1" });

// Regle 4 : routine cafe matin (prediction IA)
if (piece === "cuisine" && pr.cuisine && pr.cuisine.activity_prob > 0.6 && h >= 6 && h <= 9)
    out.push({ topic:"smarthome/cuisine/coffee/set", payload:"1" });

if (out.length === 0) return null;
node.status({fill:"yellow", shape:"dot", text: out.length + " action(s)"});
return [ out ];

// Parser predictions : smarthome/predictions/<piece>
var p = msg.topic.split("/");
var piece = p[2];
var pr = flow.get("predictions") || {};
try { pr[piece] = Object.assign(pr[piece] || {}, JSON.parse(msg.payload)); } catch(e) {}
flow.set("predictions", pr);
node.status({fill:"blue", shape:"dot", text:"pred " + piece});
return msg;

// Registre des capteurs (publie par le HUD, retenu)
try {
    var reg = JSON.parse(msg.payload);
    flow.set("sensors", reg);
    node.status({fill:"blue", shape:"dot", text: reg.length + " capteurs declares"});
} catch(e) { node.warn("registre invalide"); }
return null;

// Mode presence (smarthome/mode : present|away)
var m = (""+msg.payload).trim();
if (m === "present" || m === "away") { global.set("mode", m); node.status({text:"mode " + m}); }
return null;

// Expose l'etat courant en JSON (fallback pour le HUD)
msg.payload = {
    state: flow.get("state") || {},
    predictions: flow.get("predictions") || {},
    sensors: flow.get("sensors") || [],
    mode: global.get("mode") || "present",
    ts: Date.now()
};
msg.headers = { "Access-Control-Allow-Origin":"*", "Content-Type":"application/json" };
return msg;
